SELECT id, name, mobile, email, status, create_at, update_at
FROM user


        AND name like CONCAT(#{param.name}, '%')


        AND mobile = #{param.mobile}


        AND email = #{param.email}


        AND status = #{param.status}

    AND name != 'admin'

